// Pull in the bot's current config and build the Claude digest prompt.
const status = $input.first().json;

// Format today's date in IST
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const istDate = new Date(now.getTime() + istOffset);
const dateStr = istDate.toISOString().slice(0, 10);

const prompt = `You are the daily operations analyst for an INR/USDT spread arbitrage bot on CoinSwitch India.

Today: ${dateStr}

Current bot config:
- min_spread_pct: ${(status.min_spread_pct * 100).toFixed(2)}% (must exceed cost floor of ~1.08%)
- two_leg_enabled: ${status.two_leg_enabled}
- three_leg_enabled: ${status.three_leg_enabled}
- taker_fee: ${(status.taker_fee * 100).toFixed(3)}%
- tds_rate: ${(status.tds_rate * 100).toFixed(1)}% (TDS is the dominant cost)

Market context:
- The 2-leg strategy buys S on INR market and sells on USDT C2C (or reverse).
- Current market is calm — typical spreads run 0.3–0.8% raw, well below 1.5% threshold.
- TDS at 1% means the net spread after costs is usually negative.
- Threshold can be hot-changed via the control API without restarting the bot.

Write a concise daily ops digest (max 8 bullet points) covering:
1. Whether current min_spread_pct is calibrated correctly for current market
2. One recommendation for today (e.g., watch for news-driven volatility, a symbol to watch, a threshold experiment to try)
3. Current risk posture (is the bot too conservative, too aggressive, or well-calibrated?)

End with a one-line summary for the Slack message title.`;

return [{
  json: {
    status,
    dateStr,
    claudeRequest: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 600,
      messages: [{ role: 'user', content: prompt }]
    }
  }
}];

// Extract Claude's digest text and format for Slack.
const claudeBody = $input.first().json;
const prev       = $('Build Digest Prompt').first().json;

const rawText = claudeBody.content?.[0]?.text || 'No response from Claude.';

// Split the last line off as a title if Claude followed the format.
const lines = rawText.trim().split('\n').filter(l => l.trim());
const lastLine = lines[lines.length - 1];
const isTitle = lastLine && !lastLine.startsWith('-') && !lastLine.startsWith('•') && !lastLine.startsWith('*');

const title = isTitle ? lastLine : `Daily Arb Digest — ${prev.dateStr}`;
const body  = isTitle ? lines.slice(0, -1).join('\n') : rawText;

const slackPayload = {
  username: 'ArbAgent',
  text: `:bar_chart: *${title}*\n\n${body}\n\n_Config: spread=${(prev.status.min_spread_pct * 100).toFixed(2)}%  2leg=${prev.status.two_leg_enabled}  3leg=${prev.status.three_leg_enabled}_`
};

return [{ json: slackPayload }];
